local GC = GuildForge

GC.EXP_CLASSIC = 1
GC.EXP_TBC     = 2
GC.EXP_WOTLK   = 3
GC.EXP_CATA    = 4
GC.EXP_MOP     = 5
GC.EXP_WOD     = 6

local CLASSIC = GC.EXP_CLASSIC
local TBC     = GC.EXP_TBC
local WOTLK   = GC.EXP_WOTLK
local CATA    = GC.EXP_CATA
local MOP     = GC.EXP_MOP
local WOD     = GC.EXP_WOD

GC.EXP_SHORT = {
    [CLASSIC] = "Vanilla",
    [TBC]     = "BC",
    [WOTLK]   = "WotLK",
    [CATA]    = "Cata",
    [MOP]     = "MoP",
    [WOD]     = "WoD",
}

local function DetectExpansion()
    local toc = select(4, GetBuildInfo())
    if     toc >= 60000 then return WOD
    elseif toc >= 50000 then return MOP
    elseif toc >= 40000 then return CATA
    elseif toc >= 30000 then return WOTLK
    elseif toc >= 20000 then return TBC
    else                      return CLASSIC
    end
end

GC.currentExpansion = DetectExpansion()
GC.showPrevExp = (GC.currentExpansion > CLASSIC)

